using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpToolServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The MCP SDK discovers methods marked with [McpServerTool] via reflection.
/// Constructor/method parameters resolved from DI are injected automatically.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    [McpServerTool(Name = "get_forecast"),
     Description("Get the weather forecast for a city. Returns temperature and conditions.")]
    public async Task<string> GetForecast(
        HttpClient httpClient,
        [Description("City name, e.g. \"Seattle\"")] string city,
        [Description("Number of forecast days (1-5)")] int days = 3)
    {
        // Example: https://api.weatherapi.com/v1/forecast.json?q=Seattle&days=3
        var response = await httpClient.GetAsync(
            $"forecast.json?q={Uri.EscapeDataString(city)}&days={days}");

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        return json.ToString();
    }

    [McpServerTool(Name = "get_current_weather"),
     Description("Get current weather conditions for a city.")]
    public async Task<string> GetCurrentWeather(
        HttpClient httpClient,
        [Description("City name, e.g. \"London\"")] string city)
    {
        var response = await httpClient.GetAsync(
            $"current.json?q={Uri.EscapeDataString(city)}");

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        return json.ToString();
    }
}

